class Solution:
    def numsSameConsecDiff(self, n: int, k: int) -> List[int]:
        result = []
        def backtrack(index, current_num):
            if index == n:
                result.append(current_num)
                return
            for digit in range(10):
                if index == 0 or abs(digit - current_num % 10) == k:
                    backtrack(index + 1, current_num * 10 + digit)
        backtrack(0, 0)
        return result
```
